new_func = '''/// Try to fold ceiling division by power-of-2 pattern to a logical shift right.
/// Recognizes the pattern:
///   (lshr X, C) + zext(icmp ne (and X, (1 << C) - 1), 0)
/// And folds it to:
///   lshr (add X, (1 << C) - 1), C
/// This is the idiom for computing ceil(X / (1 << C)) for non-negative X.
static Instruction *foldAddToCeilLShr(BinaryOperator &Add) {
  Value *X;
  const APInt *ShiftAmt;
  Value *LShrOp, *ZExtOp;

  // Try both operand orders since add is commutative
  if (match(Add.getOperand(0), m_LShr(m_Value(X), m_APInt(ShiftAmt)))) {
    LShrOp = Add.getOperand(0);
    ZExtOp = Add.getOperand(1);
  } else if (match(Add.getOperand(1), m_LShr(m_Value(X), m_APInt(ShiftAmt)))) {
    LShrOp = Add.getOperand(1);
    ZExtOp = Add.getOperand(0);
  } else {
    return nullptr;
  }

