  if (ShiftAmt->uge(BitWidth))
    return nullptr;

  // Compute the mask: (1 << C) - 1
  APInt Mask = APInt::getLowBitsSet(BitWidth, ShiftAmt->getZExtValue());

  // Match: zext(icmp ne (and X, Mask), 0)
  const APInt *AndMask;
  CmpPredicate Pred;
  if (!match(ZExtOp,
             m_ZExt(m_ICmp(Pred, m_And(m_Deferred(X), m_APInt(AndMask)), m_ZeroInt()))))
    return nullptr;

  // Verify: predicate is ne and mask is (1 << C) - 1
  if (Pred != ICmpInst::ICMP_NE || *AndMask != Mask)
    return nullptr;

  // Create: lshr (add X, Mask), C
  auto *AddMask = BinaryOperator::CreateAdd(
      X, ConstantInt::get(X->getType(), Mask));
  AddMask->setHasNoSignedWrap(Add.hasNoSignedWrap());
  AddMask->setHasNoUnsignedWrap(Add.hasNoUnsignedWrap());
  auto *LShr = BinaryOperator::CreateLShr(AddMask, ConstantInt::get(Add.getType(), *ShiftAmt));
  if (auto *OrigLShr = dyn_cast<BinaryOperator>(LShrOp))
    LShr->setIsExact(OrigLShr->isExact());
  return LShr;
}'''

